export {};
const canvas=document.querySelector<HTMLCanvasElement>("#mc-canvas"),method=document.querySelector<HTMLSelectElement>("#mc-method"),speed=document.querySelector<HTMLInputElement>("#mc-speed"),reset=document.querySelector<HTMLButtonElement>("#mc-reset"),readout=document.querySelector<HTMLElement>("#mc-readout");
if(canvas&&method&&speed&&reset&&readout){const ctx=canvas.getContext("2d");if(ctx)init(ctx)}
function init(ctx:CanvasRenderingContext2D){let n=0,inside=0,history:number[]=[],seed=1,paused=false;const clear=()=>{n=0;inside=0;history=[];seed++;draw(ctx,n,inside,history)};const randomize=()=>{method!.selectedIndex=Math.floor(Math.random()*method!.options.length);speed!.value=String(8+Math.floor(Math.random()*60));clear()};const resize=()=>{const r=canvas!.getBoundingClientRect(),s=devicePixelRatio||1;canvas!.width=Math.max(320,Math.floor(r.width*s));canvas!.height=Math.max(240,Math.floor(r.height*s));clear()};reset!.onclick=clear;method!.onchange=clear;window.addEventListener("incomplete:pause",(event)=>{paused=Boolean((event as CustomEvent<{paused:boolean}>).detail.paused)});window.addEventListener("incomplete:reset",clear);window.addEventListener("incomplete:randomize",randomize);new ResizeObserver(resize).observe(canvas!.parentElement??canvas!);resize();const tick=()=>{if(!paused){for(let i=0,steps=Math.round(Number(speed!.value)*sharedSpeed());i<steps;i++){const p=sample(n,seed);if(p.x*p.x+p.y*p.y<=1)inside++;n++;if(n%20===0)history.push(4*inside/n)}draw(ctx,n,inside,history)}requestAnimationFrame(tick)};tick()}
function sample(i:number,seed:number){if(method!.value==="quasi-random")return{x:halton(i+seed,2),y:halton(i+seed,3)};if(method!.value==="stratified"){const m=32,j=i%(m*m);return{x:((j%m)+Math.random())/m,y:((j/m|0)+Math.random())/m}};if(method!.value==="importance"){const r=Math.sqrt(Math.random()),a=Math.random()*Math.PI/2;return{x:Math.cos(a)*r,y:Math.sin(a)*r}}return{x:Math.random(),y:Math.random()}}
function draw(ctx:CanvasRenderingContext2D,n:number,inside:number,history:number[]){const W=canvas!.width,H=canvas!.height,box=Math.min(W*.45,H*.75),ox=W*.08,oy=H*.12;ctx.fillStyle="rgba(3,4,10,.24)";ctx.fillRect(0,0,W,H);ctx.strokeStyle="rgba(255,255,255,.2)";ctx.strokeRect(ox,oy,box,box);ctx.beginPath();ctx.arc(ox,oy+box,box, -Math.PI/2,0);ctx.stroke();for(let k=0;k<160;k++){const p=sample(n+k,7);ctx.fillStyle=p.x*p.x+p.y*p.y<=1?"rgba(94,220,170,.55)":"rgba(255,105,135,.42)";ctx.fillRect(ox+p.x*box,oy+box-p.y*box,2,2)}const gx=W*.6,gy=H*.2,gw=W*.32,gh=H*.5;ctx.strokeStyle="rgba(255,255,255,.18)";ctx.strokeRect(gx,gy,gw,gh);ctx.strokeStyle="#ffd36b";ctx.beginPath();history.slice(-240).forEach((v,i)=>{const x=gx+i/239*gw,y=gy+gh-(v-2.6)/1.0*gh;i?ctx.lineTo(x,y):ctx.moveTo(x,y)});ctx.stroke();ctx.strokeStyle="rgba(255,255,255,.35)";ctx.beginPath();ctx.moveTo(gx,gy+gh-(Math.PI-2.6)*gh);ctx.lineTo(gx+gw,gy+gh-(Math.PI-2.6)*gh);ctx.stroke();const estimate=n?4*inside/n:0;readout!.textContent=`${method!.value} · π≈${estimate.toFixed(5)} · error ${Math.abs(Math.PI-estimate).toFixed(5)}`}
function halton(i:number,b:number){let f=1,r=0;while(i>0){f/=b;r+=f*(i%b);i=Math.floor(i/b)}return r}
function sharedSpeed(){return Number(document.querySelector<HTMLInputElement>("[data-control-speed]")?.value??"1")}

